1	/**
2	 * SQLite backend for The Stacks — backed by better-sqlite3.
3	 *
4	 * Implements the StacksBackend interface. All SQLite-specific details
5	 * (json_extract, table naming, WAL mode) are encapsulated here.
6	 *
7	 * Documents are stored as JSON blobs in a `content` TEXT column.
8	 * Field queries use json_extract() against declared indexes.
9	 */
10	
11	import path from 'node:path';
12	import Database from 'better-sqlite3';
13	import type { Database as DB } from 'better-sqlite3';
14	
15	import type {
16	  BackendOptions,
17	  BackendTransaction,
18	  BookRef,
19	  CountQuery,
20	  DeleteResult,
21	  InternalCondition,
22	  InternalQuery,
23	  PatchResult,
24	  PutResult,
25	  StacksBackend,
26	} from './backend.ts';
27	import type { BookEntry, BookSchema } from './types.ts';
28	import { validateFieldName } from './query.ts';
29	
30	// ── Table naming ──────────────────────────────────────────────────────
31	
32	const SAFE_BOOK_NAME_RE = /^[A-Za-z0-9_-]+$/;
33	
34	function normalizeOwnerId(ownerId: string): string {
35	  return ownerId.replace(/\//g, '__').replace(/[^a-z0-9_]/g, '_');
36	}
37	
38	export function tableName(ref: BookRef): string {
39	  if (!SAFE_BOOK_NAME_RE.test(ref.book)) {
40	    throw new Error(`[stacks/sqlite] Unsafe book name rejected: "${ref.book}"`);
41	  }
42	  return `books_${normalizeOwnerId(ref.ownerId)}_${ref.book}`;
43	}
44	
45	// ── JSON path helpers ─────────────────────────────────────────────────
46	
47	function toJsonPath(field: string): string {
48	  return '$.' + validateFieldName(field);
49	}
50	
