1	/**
2	 * Stacks core — shared implementation logic for both the production
3	 * apparatus (stacks.ts) and the testable harness (testable-stacks.ts).
4	 *
5	 * This module contains ALL read/write/transaction/CDC logic. The two
6	 * consumer modules only add their own wiring: the apparatus adds guild()
7	 * startup and plugin schema reconciliation; the testable harness adds
8	 * nothing (just exposes createApi() directly).
9	 *
10	 * This ensures behavioral identity by construction, not by copy-paste.
11	 */
12	
13	import type {
14	  BackendTransaction,
15	  BookRef,
16	  InternalQuery,
17	  StacksBackend,
18	} from './backend.ts';
19	
20	import type {
21	  Book,
22	  BookEntry,
23	  BookQuery,
24	  ListOptions,
25	  ReadOnlyBook,
26	  StacksApi,
27	  TransactionContext,
28	  WatchOptions,
29	  WhereClause,
30	  ChangeHandler,
31	} from './types.ts';
32	
33	import {
34	  CdcRegistry,
35	  coalesceEvents,
36	  Phase2DepthExceededError,
37	  type BufferedEvent,
38	} from './cdc.ts';
39	import { translateQuery, translateWhereClause } from './query.ts';
40	import { normalizeOrderBy, compareByOrderEntries } from './field-utils.ts';
41	
42	// ── Constants ────────────────────────────────────────────────────────
43	
44	/**
45	 * Phase-1 cascade-depth bound — caps in-transaction handler nesting so
46	 * a Phase-1 watcher that re-triggers itself cannot pin the CPU. Counted
47	 * per-transaction inside `ActiveTransaction.depth`.
48	 */
49	const MAX_CASCADE_DEPTH = 16;
50	
51	/**
52	 * Phase-2 cross-transaction re-entry depth bound — caps the number of
53	 * post-commit handler hops in a single Phase-2 chain. The Phase-1 guard
54	 * resets when each Phase-2 handler opens its own transaction, so a
55	 * separate counter is required to bound Phase-2 cycles. Counted at the
56	 * `firePhase2` boundary inside `phase2Depth` (D3, D4, D5).
57	 *
58	 * The two bounds are intentionally orthogonal: Phase-1 measures handler
59	 * nesting within one transaction; Phase-2 measures post-commit hops
60	 * across transactions. Sharing a single budget would false-positive
61	 * deep cascade graphs.
62	 */
63	const MAX_PHASE2_REENTRY_DEPTH = 16;
64	
65	// ── Active transaction state ──────────────────────────────────────────
66	
67	interface ActiveTransaction {
68	  backendTx: BackendTransaction;
69	  eventBuffer: BufferedEvent[];
70	  depth: number;
71	}
72	
73	// ── Book handle implementation ────────────────────────────────────────
74	
75	function createBookHandle<T extends BookEntry>(
76	  ref: BookRef,
77	  core: StacksCore,
78	  writable: boolean,
79	): Book<T> {
80	  const readMethods: ReadOnlyBook<T> = {
81	    async get(id: string): Promise<T | null> {
82	      return core.doGet(ref, id) as T | null;
83	    },
84	
85	    async find(query: BookQuery): Promise<T[]> {
86	      return core.doFind(ref, query) as Promise<T[]>;
87	    },
88	
89	    async list(options?: ListOptions): Promise<T[]> {
90	      // Cast needed: ListOptions spreads into BookQuery but the Pagination
91	      // discriminated union can't be inferred from optional fields.
92	      return core.doFind(ref, {
93	        orderBy: options?.orderBy,
94	        limit: options?.limit,
95	        offset: options?.offset,
96	      } as BookQuery) as Promise<T[]>;
97	    },
98	
99	    async count(where?: WhereClause | { or: WhereClause[] }): Promise<number> {
100	      return core.doCount(ref, where);
101	    },
102	  };
103	
104	  if (!writable) {
105	    return readMethods as Book<T>;
106	  }
107	
108	  return {
109	    ...readMethods,
110	
111	    async put(entry: T): Promise<void> {
112	      await core.doPut(ref, entry);
113	    },
114	
115	    async patch(id: string, fields: Partial<Omit<T, 'id'>>): Promise<T> {
116	      return (await core.doPatch(ref, id, fields as Record<string, unknown>)) as T;
117	    },
118	
119	    async delete(id: string): Promise<void> {
120	      await core.doDelete(ref, id);
121	    },
122	  };
123	}
124	
125	// ── Stacks core implementation ───────────────────────────────────────
126	
127	export class StacksCore {
128	  private readonly cdc = new CdcRegistry();
129	  private activeTx: ActiveTransaction | null = null;
130	
131	  /**
132	   * Phase-2 cross-transaction re-entry depth (D2). Mirrors the
133	   * `activeTx` instance-field pattern — single-flight per apparatus
134	   * instance, no AsyncLocalStorage. Incremented when entering a
135	   * `firePhase2` invocation and decremented on exit; gate-checked at
136	   * the next `runTransaction` entry so a runaway Phase-2 self-write
137	   * chain fails loud rather than pinning the CPU. See `runTransaction`
138	   * for the gate check (D6) and the firePhase2 wrapper (D5).
139	   */
140	  private phase2Depth = 0;
141	
142	  constructor(readonly backend: StacksBackend) {}
143	
144	  /**
145	   * Seal the CDC registry. After this is called, any further `watch()`
146	   * calls throw. Invoked by the guild runtime (arbor) via the
147	   * `phase:started` event, after all apparatus start() methods complete,
148	   * so startup-time writes in one apparatus don't lock out watcher
149	   * registration in a dependent apparatus that starts later.
150	   */
151	  sealCdc(): void {
152	    this.cdc.lock();
153	  }
154	
155	  // ── API surface ───────────────────────────────────────────────────
156	
157	  createApi(): StacksApi {
158	    const self = this;
159	
160	    return {
161	      book<T extends BookEntry>(ownerId: string, name: string): Book<T> {
162	        return createBookHandle<T>({ ownerId, book: name }, self, true);
163	      },
164	
165	      readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T> {
166	        return createBookHandle<T>({ ownerId, book: name }, self, false) as ReadOnlyBook<T>;
167	      },
168	
169	      watch<T extends BookEntry>(
170	        ownerId: string,
171	        bookName: string,
172	        handler: ChangeHandler<T>,
173	        options?: WatchOptions,
174	      ): void {
175	        self.cdc.watch(
176	          ownerId,
177	          bookName,
178	          handler as ChangeHandler,
179	          options,
180	        );
181	      },
182	
183	      async transaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
184	        return self.runTransaction(fn);
185	      },
186	    };
187	  }
188	
189	  // ── Transaction management ────────────────────────────────────────
190	
191	  async runTransaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
192	    // If already in a transaction, just run (no nesting — flattened)
193	    if (this.activeTx) {
194	      const txCtx = this.createTransactionContext();
195	      return fn(txCtx);
196	    }
197	
198	    // Phase-2 cross-transaction re-entry bound (gate-entry, D5/D6).
199	    // If we're being entered from within a Phase-2 handler chain that
200	    // has already accumulated MAX_PHASE2_REENTRY_DEPTH hops, refuse to
201	    // open a new backend transaction so the offending handler write is
202	    // rejected (D10 partial-commit) and the chain terminates loud.
203	    // The throw fires before the try/catch below so the existing
204	    // rollback path — which only handles tx-level failures — is not
205	    // engaged for a transaction that was never opened.
206	    if (this.phase2Depth >= MAX_PHASE2_REENTRY_DEPTH) {
207	      throw new Phase2DepthExceededError(MAX_PHASE2_REENTRY_DEPTH);
208	    }
209	
210	    // Create new transaction
211	    const backendTx = this.backend.beginTransaction();
212	    const eventBuffer: BufferedEvent[] = [];
213	    this.activeTx = { backendTx, eventBuffer, depth: 0 };
214	
215	    try {
216	      const txCtx = this.createTransactionContext();
217	      const result = await fn(txCtx);
218	
219	      backendTx.commit();
220	      const coalesced = coalesceEvents(eventBuffer);
221	      this.activeTx = null;
222	
223	      // Fire Phase 2 handlers (after commit). Wrap with depth tracking
224	      // so the substrate-level cross-transaction re-entry bound (D5)
225	      // sees the correct hop count when a handler triggers another
226	      // Phase-2 chain. The increment must happen even though the gate
227	      // check fires in the *next* runTransaction call — that next call
228	      // reads `phase2Depth` to decide whether to refuse the write.
229	      this.phase2Depth++;
230	      try {
231	        await this.cdc.firePhase2(coalesced);
232	      } finally {
233	        this.phase2Depth--;
234	      }
235	
236	      return result;
237	    } catch (err) {
238	      try { backendTx.rollback(); } catch { /* already rolled back */ }
239	      this.activeTx = null;
240	      throw err;
241	    }
242	  }
243	
244	  private createTransactionContext(): TransactionContext {
245	    const self = this;
246	    return {
247	      book<T extends BookEntry>(ownerId: string, name: string): Book<T> {
248	        return createBookHandle<T>({ ownerId, book: name }, self, true);
249	      },
250	      readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T> {
251	        return createBookHandle<T>({ ownerId, book: name }, self, false) as ReadOnlyBook<T>;
252	      },
253	    };
254	  }
255	
256	  // ── Write operations (called by book handles) ─────────────────────
257	
258	  async doPut(ref: BookRef, entry: BookEntry): Promise<void> {
259	    if (!this.activeTx) {
260	      return this.runTransaction(async () => this.doPutInTx(ref, entry));
261	    }
262	    return this.doPutInTx(ref, entry);
263	  }
264	
265	  private async doPutInTx(ref: BookRef, entry: BookEntry): Promise<void> {
266	    const tx = this.requireTx();
267	
268	    // Check cascade depth
269	    tx.depth++;
270	    if (tx.depth > MAX_CASCADE_DEPTH) {
271	      throw new Error(
272	        `[stacks] Maximum cascade depth (${MAX_CASCADE_DEPTH}) exceeded. ` +
273	        `This usually means a CDC handler is triggering itself recursively.`,
274	      );
275	    }
276	
277	    const needPrev = this.cdc.hasWatchers(ref.ownerId, ref.book);
278	    const result = tx.backendTx.put(ref, entry, { withPrev: needPrev });
279	
280	    const event: BufferedEvent = {
281	      ref: `${ref.ownerId}/${ref.book}`,
282	      ownerId: ref.ownerId,
283	      book: ref.book,
284	      docId: entry.id,
285	      type: result.created ? 'create' : 'update',
286	      entry,
287	      prev: result.prev,
288	    };
289	    tx.eventBuffer.push(event);
290	
291	    // Fire Phase 1 handlers (inside the transaction)
292	    if (result.created) {
293	      await this.cdc.firePhase1(ref.ownerId, ref.book, {
294	        type: 'create', ownerId: ref.ownerId, book: ref.book, entry,
295	      });
296	    } else {
297	      await this.cdc.firePhase1(ref.ownerId, ref.book, {
298	        type: 'update', ownerId: ref.ownerId, book: ref.book, entry, prev: result.prev!,
299	      });
300	    }
301	
302	    tx.depth--;
303	  }
304	
305	  async doPatch(ref: BookRef, id: string, fields: Record<string, unknown>): Promise<BookEntry> {
306	    if (!this.activeTx) {
307	      let result!: BookEntry;
308	      await this.runTransaction(async () => {
309	        result = await this.doPatchInTx(ref, id, fields);
310	      });
311	      return result;
312	    }
313	    return this.doPatchInTx(ref, id, fields);
314	  }
315	
316	  private async doPatchInTx(
317	    ref: BookRef,
318	    id: string,
319	    fields: Record<string, unknown>,
320	  ): Promise<BookEntry> {
321	    const tx = this.requireTx();
322	
323	    tx.depth++;
324	    if (tx.depth > MAX_CASCADE_DEPTH) {
325	      throw new Error(
326	        `[stacks] Maximum cascade depth (${MAX_CASCADE_DEPTH}) exceeded.`,
327	      );
328	    }
329	
330	    const result = tx.backendTx.patch(ref, id, fields);
331	
332	    const event: BufferedEvent = {
333	      ref: `${ref.ownerId}/${ref.book}`,
334	      ownerId: ref.ownerId,
335	      book: ref.book,
336	      docId: id,
337	      type: 'update',
338	      entry: result.entry,
339	      prev: result.prev,
340	    };
341	    tx.eventBuffer.push(event);
342	
343	    await this.cdc.firePhase1(ref.ownerId, ref.book, {
344	      type: 'update', ownerId: ref.ownerId, book: ref.book,
345	      entry: result.entry, prev: result.prev,
346	    });
347	
348	    tx.depth--;
349	
350	    return result.entry;
351	  }
352	
353	  async doDelete(ref: BookRef, id: string): Promise<void> {
354	    if (!this.activeTx) {
355	      return this.runTransaction(async () => this.doDeleteInTx(ref, id));
356	    }
357	    return this.doDeleteInTx(ref, id);
358	  }
359	
360	  private async doDeleteInTx(ref: BookRef, id: string): Promise<void> {
361	    const tx = this.requireTx();
362	
363	    tx.depth++;
364	    if (tx.depth > MAX_CASCADE_DEPTH) {
365	      throw new Error(
366	        `[stacks] Maximum cascade depth (${MAX_CASCADE_DEPTH}) exceeded.`,
367	      );
368	    }
369	
370	    const needPrev = this.cdc.hasWatchers(ref.ownerId, ref.book);
371	    const result = tx.backendTx.delete(ref, id, { withPrev: needPrev });
372	
373	    if (!result.found) {
374	      tx.depth--;
375	      return; // Silent no-op
376	    }
377	
378	    const event: BufferedEvent = {
379	      ref: `${ref.ownerId}/${ref.book}`,
380	      ownerId: ref.ownerId,
381	      book: ref.book,
382	      docId: id,
383	      type: 'delete',
384	      prev: result.prev,
385	    };
386	    tx.eventBuffer.push(event);
387	
388	    await this.cdc.firePhase1(ref.ownerId, ref.book, {
389	      type: 'delete', ownerId: ref.ownerId, book: ref.book, id, prev: result.prev!,
390	    });
391	
392	    tx.depth--;
393	  }
394	
395	  // ── Read operations ───────────────────────────────────────────────
396	
397	  doGet(ref: BookRef, id: string): BookEntry | null {
398	    if (this.activeTx) {
399	      return this.activeTx.backendTx.get(ref, id);
400	    }
401	    // Outside a transaction — use a throwaway read transaction
402	    const tx = this.backend.beginTransaction();
403	    try {
404	      const result = tx.get(ref, id);
405	      tx.commit();
406	      return result;
407	    } catch (err) {
408	      tx.rollback();
409	      throw err;
410	    }
411	  }
412	
413	  async doFind(ref: BookRef, query: BookQuery): Promise<BookEntry[]> {
414	    // Handle OR queries at the apparatus level
415	    if (query.where && !Array.isArray(query.where) && 'or' in query.where) {
416	      return this.doFindOr(ref, query);
417	    }
418	
419	    const internal = translateQuery(query as BookQuery & { where?: WhereClause });
420	    if (this.activeTx) {
421	      return this.activeTx.backendTx.find(ref, internal);
422	    }
423	    const tx = this.backend.beginTransaction();
424	    try {
425	      const result = tx.find(ref, internal);
426	      tx.commit();
427	      return result;
428	    } catch (err) {
429	      tx.rollback();
430	      throw err;
431	    }
432	  }
433	
434	  /**
435	   * OR queries: run each branch as a separate backend query, deduplicate
436	   * by id, re-sort, and paginate the merged result set.
437	   *
438	   * V1 trade-off: when called outside an active transaction, each branch
439	   * opens its own throwaway read transaction. For synchronous backends
440	   * like better-sqlite3, the data can't change between branches so this
441	   * is safe. A hypothetical async backend could see different snapshots
442	   * per branch, producing inconsistent results — a known limitation
443	   * documented in the spec's implementation notes.
444	   *
445	   * Performance note: each branch is a separate backend query. count()
446	   * with OR cannot use the backend's efficient count path since
447	   * deduplication requires knowing which IDs overlap. Acceptable for v1.
448	   */
449	  private async doFindOr(ref: BookRef, query: BookQuery): Promise<BookEntry[]> {
450	    const orClauses = (query.where as { or: WhereClause[] }).or;
451	
452	    if (orClauses.length === 0) return [];
453	
454	    const seen = new Set<string>();
455	    const merged: BookEntry[] = [];
456	
457	    const runBranch = (branch: WhereClause): BookEntry[] => {
458	      const branchQuery = translateQuery({ where: branch } as BookQuery & { where?: WhereClause });
459	      if (this.activeTx) {
460	        return this.activeTx.backendTx.find(ref, branchQuery);
461	      }
462	      const tx = this.backend.beginTransaction();
463	      try {
464	        const result = tx.find(ref, branchQuery);
465	        tx.commit();
466	        return result;
467	      } catch (err) {
468	        tx.rollback();
469	        throw err;
470	      }
471	    };
472	
473	    for (const branch of orClauses) {
474	      const results = runBranch(branch);
475	      for (const entry of results) {
476	        if (!seen.has(entry.id)) {
477	          seen.add(entry.id);
478	          merged.push(entry);
479	        }
480	      }
481	    }
482	
483	    // Apply sorting
484	    if (query.orderBy) {
485	      const orderEntries = normalizeOrderBy(query.orderBy);
486	      merged.sort((a, b) => compareByOrderEntries(a, b, orderEntries));
487	    }
488	
489	    // Apply pagination
490	    let result = merged;
491	    if (query.offset !== undefined) {
492	      result = result.slice(query.offset);
493	    }
494	    if (query.limit !== undefined) {
495	      result = result.slice(0, query.limit);
496	    }
497	
498	    return result;
499	  }
500	
501	  async doCount(ref: BookRef, where?: WhereClause | { or: WhereClause[] }): Promise<number> {
502	    // Handle OR queries — must deduplicate, so use doFindOr
503	    if (where && !Array.isArray(where) && 'or' in where) {
504	      const results = await this.doFindOr(ref, { where } as BookQuery);
505	      return results.length;
506	    }
507	
508	    const internal = translateWhereClause(where as WhereClause | undefined);
509	    if (this.activeTx) {
510	      return this.activeTx.backendTx.count(ref, internal);
511	    }
512	    const tx = this.backend.beginTransaction();
513	    try {
514	      const result = tx.count(ref, internal);
515	      tx.commit();
516	      return result;
517	    } catch (err) {
518	      tx.rollback();
519	      throw err;
520	    }
521	  }
522	
523	  private requireTx(): ActiveTransaction {
524	    if (!this.activeTx) {
525	      throw new Error('[stacks] Write operation outside transaction — this is a bug');
526	    }
527	    return this.activeTx;
528	  }
529	}
