1	/**
2	 * Tier 4 — Edge Cases and Ergonomics conformance tests.
3	 */
4	
5	import { describe, it, beforeEach, afterEach } from 'node:test';
6	import assert from 'node:assert/strict';
7	
8	import type { StacksBackend } from '../backend.ts';
9	import type { BookEntry } from '../types.ts';
10	import { createTestStacks, OWNER, BOOK, REF, type TestStacks } from './helpers.ts';
11	
12	export function tier4EdgeCases(backendFactory: () => StacksBackend): void {
13	  describe('Tier 4 — Edge Cases and Ergonomics', () => {
14	    let t: TestStacks;
15	
16	    beforeEach(() => {
17	      t = createTestStacks(backendFactory);
18	      t.ensureBook(OWNER, BOOK);
19	    });
20	
21	    afterEach(() => {
22	      t.backend.close();
23	    });
24	
25	    it('4.1 Cross-plugin read isolation', async () => {
26	      const writeHandle = t.stacks.book<BookEntry>(OWNER, BOOK);
27	      const readHandle = t.stacks.readBook<BookEntry>(OWNER, BOOK);
28	
29	      await writeHandle.put({ id: 'a', title: 'test' });
30	      const result = await readHandle.get('a');
31	      assert.deepStrictEqual(result, { id: 'a', title: 'test' });
32	
33	      // Read handle must NOT expose write methods
34	      assert.strictEqual((readHandle as any).put, undefined);
35	      assert.strictEqual((readHandle as any).patch, undefined);
36	      assert.strictEqual((readHandle as any).delete, undefined);
37	    });
38	
39	    it('4.2 Books are isolated by owner + name', async () => {
40	      const ownerA = 'plugin-a';
41	      const ownerB = 'plugin-b';
42	      const bookName = 'items';
43	      t.ensureBook(ownerA, bookName);
44	      t.ensureBook(ownerB, bookName);
45	
46	      const bookA = t.stacks.book<BookEntry>(ownerA, bookName);
47	      const bookB = t.stacks.book<BookEntry>(ownerB, bookName);
48	
49	      await bookA.put({ id: 'x', name: 'A-item' });
50	      await bookB.put({ id: 'x', name: 'B-item' });
51	
52	      const resultA = await bookA.get('x');
53	      const resultB = await bookB.get('x');
54	      assert.deepStrictEqual(resultA, { id: 'x', name: 'A-item' });
55	      assert.deepStrictEqual(resultB, { id: 'x', name: 'B-item' });
56	    });
57	
58	    it('4.3 Watch registration after CDC seal throws', async () => {
59	      // Writes during startup are allowed — they no longer lock the
60	      // registry. Sealing happens when arbor fires `phase:started`,
61	      // after every apparatus has finished starting. The test harness
62	      // exposes `sealCdc()` to simulate that moment.
63	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
64	      await book.put({ id: 'a', name: 'Alice' });
65	
66	      // Before seal: watch() is still accepted even after a write.
67	      assert.doesNotThrow(() =>
68	        t.stacks.watch(OWNER, BOOK, () => {}),
69	      );
70	
71	      t.sealCdc();
72	
73	      // After seal: further watch() calls throw.
74	      assert.throws(
75	        () => t.stacks.watch(OWNER, BOOK, () => {}),
76	        /watch.*startup|locked/i,
77	      );
78	    });
79	
80	    it('4.4 Large document round-trip', async () => {
81	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
82	
83	      // Generate a large nested structure (~100KB)
84	      const data: Record<string, unknown> = {};
85	      for (let i = 0; i < 100; i++) {
86	        data[`key${i}`] = {
87	          nested: Array.from({ length: 100 }, (_, j) => ({
88	            index: j,
89	            value: `item-${i}-${j}`,
90	          })),
91	        };
92	      }
93	
94	      const doc = { id: 'big', data };
95	      await book.put(doc);
96	      const result = await book.get('big');
97	      assert.deepStrictEqual(result, doc);
98	    });
99	
100	    it('4.5 Special characters in string values', async () => {
101	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
102	      const doc = {
103	        id: 'a',
104	        name: "O'Brien",
105	        note: 'Line1\nLine2',
106	        data: '{"json":"in a string"}',
107	      };
108	      await book.put(doc);
109	      const result = await book.get('a');
110	      assert.deepStrictEqual(result, doc);
111	    });
112	
113	    it('4.6 Boolean and numeric type fidelity in queries', async () => {
114	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
115	      await book.put({ id: 'a', active: true, count: 0 });
116	      await book.put({ id: 'b', active: false, count: 1 });
117	
118	      const trueResults = await book.find({ where: [['active', '=', true]] });
119	      assert.strictEqual(trueResults.length, 1);
120	      assert.strictEqual(trueResults[0].id, 'a');
121	
122	      const falseResults = await book.find({ where: [['active', '=', false]] });
123	      assert.strictEqual(falseResults.length, 1);
