1	/**
2	 * Tier 2.5 — Transaction Semantics conformance tests.
3	 */
4	
5	import { describe, it, beforeEach, afterEach } from 'node:test';
6	import assert from 'node:assert/strict';
7	
8	import type { StacksBackend } from '../backend.ts';
9	import type { BookEntry } from '../types.ts';
10	import { createTestStacks, OWNER, BOOK, type TestStacks } from './helpers.ts';
11	
12	export function tier25Transactions(backendFactory: () => StacksBackend): void {
13	  describe('Tier 2.5 — Transaction Semantics', () => {
