export interface StacksApi {
  book<T extends BookEntry>(ownerId: string, name: string): Book<T>;
  readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T>;

  watch<T extends BookEntry>(
    ownerId: string,
    bookName: string,
    handler: ChangeHandler<T>,
    options?: WatchOptions,
  ): void;

  transaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R>;

  /**
   * Retire a book — drops the backend table (or memory entry) and any
   * associated indexes. Idempotent: dropping a book that does not exist is
   * a silent no-op.
   *
   * Fires a single `delete-book` CDC event after the drop completes. No
   * per-row `delete` events are emitted — subscribers that cared about
   * content within the book see only the wholesale signal.
   *
   * `dropBook` is a schema-level operation and may not be called inside an
   * explicit `transaction()`. Calling it inside one throws. The drop is not
   * transactional with document writes — once the backend method returns,
   * the book is gone.
   *
   * Intended use: one-shot startup migrations or operator tooling that
   * retires a book that is no longer declared by any kit. Not for runtime
   * data lifecycle management.
   */
  dropBook(ownerId: string, bookName: string): Promise<void>;
}

