  dropBook(ref: BookRef): void {
    const db = this.requireDb();
    const table = tableName(ref);

    // Look up associated indexes via SQLite's catalog so that any historic
    // indexes — including ones declared by an earlier schema and no longer
    // present in the current `BookSchema` — are dropped along with the
    // table. Index names follow the `idx_<table>_<field>` convention used
    // by `ensureBook`, so prefix-matching against the table name is enough
    // to catch all of them.
    const idxRows = db
      .prepare(
        `SELECT name FROM sqlite_master
         WHERE type = 'index' AND tbl_name = ?`,
      )
      .all(table) as Array<{ name: string }>;

    for (const { name } of idxRows) {
      // Skip auto-indexes (e.g. those backing UNIQUE/PRIMARY KEY); they
      // are dropped automatically when the table goes.
      if (name.startsWith('sqlite_autoindex_')) continue;
      db.exec(`DROP INDEX IF EXISTS "${name}"`);
    }

    // DROP TABLE IF EXISTS — idempotent; SQLite is silent if the table is
    // already gone. This is the wholesale retirement primitive.
    db.exec(`DROP TABLE IF EXISTS "${table}"`);
  }

  beginTransaction(): BackendTransaction {
    return new SqliteTransaction(this.requireDb());
  }

  private requireDb(): DB {
    if (!this.db) {
      throw new Error('[stacks/sqlite] Backend not open — call open() first');
    }
    return this.db;
  }
}

