   * during a row write would muddy partial-commit reasoning.
   *
   * Errors thrown by `delete-book` handlers are logged and swallowed —
   * the drop is irreversible by the time the event fires.
   */
  async doDropBook(ref: BookRef): Promise<void> {
    if (this.activeTx) {
      throw new Error(
        '[stacks] dropBook() cannot be called inside an active transaction. ' +
        'Drop schema-level state outside any open transaction.',
      );
    }

    this.backend.dropBook(ref);

    await this.cdc.fireDeleteBook(ref.ownerId, ref.book);
  }

  private requireTx(): ActiveTransaction {
    if (!this.activeTx) {
      throw new Error('[stacks] Write operation outside transaction — this is a bug');
    }
    return this.activeTx;
  }
}

