    it('1.12 dropBook removes all documents wholesale', async () => {
      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
      await book.put({ id: 'a', name: 'Alice' });
      await book.put({ id: 'b', name: 'Bob' });
      await book.put({ id: 'c', name: 'Charlie' });

      assert.strictEqual(await book.count(), 3);

      await t.stacks.dropBook(OWNER, BOOK);

      // Re-create the book so reads succeed (otherwise SQLite would
      // raise "no such table" — the drop is wholesale, schema and all).
      t.ensureBook(OWNER, BOOK);

      const fresh = t.stacks.book<BookEntry>(OWNER, BOOK);
      assert.strictEqual(await fresh.get('a'), null);
      assert.strictEqual(await fresh.get('b'), null);
      assert.strictEqual(await fresh.get('c'), null);
      assert.strictEqual(await fresh.count(), 0);
    });

    it('1.13 dropBook is idempotent', async () => {
      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
      await book.put({ id: 'a', name: 'Alice' });

      // First drop succeeds.
      await t.stacks.dropBook(OWNER, BOOK);

      // Second drop on the now-empty book is a silent no-op.
      await assert.doesNotReject(() => t.stacks.dropBook(OWNER, BOOK));

      // Drop on a never-existed book is also a silent no-op.
      await assert.doesNotReject(() => t.stacks.dropBook(OWNER, 'never-existed'));
    });

    it('1.14 dropBook then ensureBook yields a fresh empty book', async () => {
      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
      await book.put({ id: 'a', name: 'Alice' });
      await book.put({ id: 'b', name: 'Bob' });

      await t.stacks.dropBook(OWNER, BOOK);
      t.ensureBook(OWNER, BOOK);

      const fresh = t.stacks.book<BookEntry>(OWNER, BOOK);
      assert.strictEqual(await fresh.count(), 0);

      // The new book must accept writes and reads correctly.
      await fresh.put({ id: 'z', name: 'Zoe' });
      assert.deepStrictEqual(await fresh.get('z'), { id: 'z', name: 'Zoe' });
    });

    it('1.15 dropBook of one book leaves sibling books untouched', async () => {
      const otherBook = 'otherbook';
      t.ensureBook(OWNER, otherBook);

      const main = t.stacks.book<BookEntry>(OWNER, BOOK);
      const other = t.stacks.book<BookEntry>(OWNER, otherBook);

      await main.put({ id: 'a', name: 'Alice' });
      await other.put({ id: 'x', name: 'Xander' });

      await t.stacks.dropBook(OWNER, BOOK);

      // The sibling book must remain intact.
      assert.deepStrictEqual(await other.get('x'), { id: 'x', name: 'Xander' });
      assert.strictEqual(await other.count(), 1);
    });

    it('1.16 dropBook with same name but different owner leaves owner-A book intact', async () => {
      const ownerA = 'plugin-a';
      const ownerB = 'plugin-b';
      const sharedName = 'items';
      t.ensureBook(ownerA, sharedName);
      t.ensureBook(ownerB, sharedName);

      const bookA = t.stacks.book<BookEntry>(ownerA, sharedName);
      const bookB = t.stacks.book<BookEntry>(ownerB, sharedName);

      await bookA.put({ id: '1', from: 'a' });
      await bookB.put({ id: '1', from: 'b' });

      await t.stacks.dropBook(ownerB, sharedName);

      // Owner A's book must be untouched — book identity is (owner, name).
      assert.deepStrictEqual(await bookA.get('1'), { id: '1', from: 'a' });
    });
  });
}

