    it('2.22 Coalescing: delete (single, existing doc) produces delete with pre-transaction prev', async () => {
      seedDocument(t.backend, REF, { id: 'a', name: 'Alice' });
      const events = collectEvents(t.stacks, OWNER, BOOK, { failOnError: false });

      await t.stacks.transaction(async (tx) => {
        const book = tx.book<BookEntry>(OWNER, BOOK);
        await book.delete('a');
      });

      assert.strictEqual(events.length, 1);
      assertDeleteEvent(events[0], { id: 'a', prev: { id: 'a', name: 'Alice' } });
    });

    // ── delete-book event (dropBook signal) ──────────────────────────

    it('2.30 dropBook fires a single delete-book event', async () => {
      const events = collectEvents(t.stacks, OWNER, BOOK, { failOnError: false });
      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
      await book.put({ id: 'a', name: 'Alice' });
      await book.put({ id: 'b', name: 'Bob' });

      // Reset the collector to focus on the drop event only.
      events.length = 0;

      await t.stacks.dropBook(OWNER, BOOK);

      // Exactly one delete-book event — no per-row delete events.
      assert.strictEqual(events.length, 1);
      assertDeleteBookEvent(events[0], { ownerId: OWNER, book: BOOK });
    });

    it('2.31 dropBook with no registered watchers fires no events', async () => {
      // No watchers registered — the drop must succeed silently.
      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
      await book.put({ id: 'a', name: 'Alice' });

      await assert.doesNotReject(() => t.stacks.dropBook(OWNER, BOOK));
    });

    it('2.32 dropBook of a never-existed book still fires delete-book to watchers', async () => {
      // Subscribers may have registered against a book they expected to
      // exist; the wholesale signal still fires so they can react.
      const ghostBook = 'ghost-book';
      const events = collectEvents(t.stacks, OWNER, ghostBook, { failOnError: false });

      await t.stacks.dropBook(OWNER, ghostBook);

      assert.strictEqual(events.length, 1);
      assertDeleteBookEvent(events[0], { ownerId: OWNER, book: ghostBook });
    });

    it('2.33 dropBook fires only to watchers of the same (ownerId, book)', async () => {
      const otherBook = 'otherbook';
      t.ensureBook(OWNER, otherBook);

      const mainEvents = collectEvents(t.stacks, OWNER, BOOK, { failOnError: false });
      const otherEvents = collectEvents(t.stacks, OWNER, otherBook, { failOnError: false });

      await t.stacks.dropBook(OWNER, BOOK);

      assert.strictEqual(mainEvents.length, 1);
      assertDeleteBookEvent(mainEvents[0], { ownerId: OWNER, book: BOOK });
      assert.strictEqual(otherEvents.length, 0);
    });

    it('2.34 dropBook handler errors do not fail the drop', async () => {
      // A delete-book handler that throws must not cause dropBook to
      // reject — the drop is irreversible by the time the event fires.
      t.stacks.watch(OWNER, BOOK, async (event) => {
        if (event.type === 'delete-book') {
          throw new Error('subscriber went bang');
        }
      }, { failOnError: false });

      await assert.doesNotReject(() => t.stacks.dropBook(OWNER, BOOK));
    });

    it('2.35 dropBook fires delete-book to BOTH Phase 1 and Phase 2 watchers', async () => {
      // The drop is a wholesale signal; both phases see it (the spec
      // notes that failOnError no longer carries meaning at this point).
      const order: string[] = [];
      t.stacks.watch(OWNER, BOOK, (event) => {
        if (event.type === 'delete-book') order.push('phase1');
      }, { failOnError: true });
      t.stacks.watch(OWNER, BOOK, (event) => {
        if (event.type === 'delete-book') order.push('phase2');
      }, { failOnError: false });

      await t.stacks.dropBook(OWNER, BOOK);

      // Both watchers fire, in registration order.
      assert.deepStrictEqual(order, ['phase1', 'phase2']);
    });

    it('2.36 dropBook inside transaction throws', async () => {
      // dropBook is schema-level; mixing it with row-level rollback
      // semantics inside an explicit transaction would muddy partial-
      // commit reasoning — and DDL implicitly commits in SQLite anyway.
      await assert.rejects(
        () => t.stacks.transaction(async () => {
          await t.stacks.dropBook(OWNER, BOOK);
        }),
        /dropBook.*transaction|transaction.*dropBook/i,
      );
    });
  });
}

