/**
 * SQLite-backend-specific tests.
 *
 * These complement the backend-agnostic conformance suite by verifying
 * SQLite-level state that the public StacksApi cannot observe — most
 * importantly, that `dropBook()` actually removes the underlying table
 * and its associated indexes from `sqlite_master`, not just the data
 * inside them. This is the precise drift that the dropBook primitive
 * was introduced to remediate (per the commission brief): retired books
 * must not leave dead tables behind on existing on-disk databases.
 */

import { describe, it, beforeEach, afterEach } from 'node:test';
import assert from 'node:assert/strict';
import os from 'node:os';
import path from 'node:path';
import fs from 'node:fs';
import Database from 'better-sqlite3';

import { SqliteBackend, tableName } from './sqlite-backend.ts';

const OWNER = 'sqlite-test-owner';
const BOOK = 'sqlite-test-book';

interface TempHome {
  home: string;
  cleanup: () => void;
}

function tempHome(): TempHome {
  const home = fs.mkdtempSync(path.join(os.tmpdir(), 'stacks-sqlite-'));
  fs.mkdirSync(path.join(home, '.nexus'), { recursive: true });
  return {
    home,
    cleanup: () => fs.rmSync(home, { recursive: true, force: true }),
  };
}

function inspectDb(home: string): Database.Database {
  return new Database(path.join(home, '.nexus', 'nexus.db'));
}

function tablesByPrefix(db: Database.Database, prefix: string): string[] {
  const rows = db
    .prepare(
      `SELECT name FROM sqlite_master
       WHERE type = 'table' AND name LIKE ?
       ORDER BY name`,
    )
    .all(`${prefix}%`) as Array<{ name: string }>;
  return rows.map((r) => r.name);
}

function indexesForTable(db: Database.Database, table: string): string[] {
  const rows = db
    .prepare(
      `SELECT name FROM sqlite_master
       WHERE type = 'index' AND tbl_name = ?
         AND name NOT LIKE 'sqlite_autoindex_%'
       ORDER BY name`,
    )
    .all(table) as Array<{ name: string }>;
  return rows.map((r) => r.name);
}

describe('SqliteBackend — dropBook removes table and indexes from sqlite_master', () => {
  let env: TempHome;
  let backend: SqliteBackend;

  beforeEach(() => {
    env = tempHome();
    backend = new SqliteBackend();
    backend.open({ home: env.home });
  });

  afterEach(() => {
    backend.close();
    env.cleanup();
  });

  it('drops the backing table from sqlite_master', () => {
    backend.ensureBook({ ownerId: OWNER, book: BOOK }, {});
    const table = tableName({ ownerId: OWNER, book: BOOK });

    // Pre-condition: the table exists.
    {
      const db = inspectDb(env.home);
      assert.ok(tablesByPrefix(db, table).includes(table));
      db.close();
    }

    backend.dropBook({ ownerId: OWNER, book: BOOK });

    // Post-condition: the table is gone — not just the rows.
    const db = inspectDb(env.home);
    assert.deepStrictEqual(tablesByPrefix(db, table), []);
    db.close();
  });

  it('drops associated indexes alongside the table', () => {
    backend.ensureBook(
      { ownerId: OWNER, book: BOOK },
      { indexes: ['status', 'createdAt', ['status', 'createdAt']] },
    );
    const table = tableName({ ownerId: OWNER, book: BOOK });

    // Pre-condition: indexes exist.
    {
      const db = inspectDb(env.home);
      const idxs = indexesForTable(db, table);
      // 3 declared indexes: status, createdAt, compound(status,createdAt)
      assert.strictEqual(idxs.length, 3, `expected 3 indexes, got: ${idxs.join(', ')}`);
      db.close();
    }

    backend.dropBook({ ownerId: OWNER, book: BOOK });

    // Post-condition: no indexes survive once the table is gone.
    const db = inspectDb(env.home);
    assert.deepStrictEqual(indexesForTable(db, table), []);
    // Belt-and-suspenders: even querying sqlite_master for indexes that
    // start with this table's idx prefix should return nothing.
    const orphans = db
      .prepare(
        `SELECT name FROM sqlite_master
         WHERE type = 'index' AND name LIKE ?`,
      )
      .all(`idx_${table}_%`) as Array<{ name: string }>;
    assert.deepStrictEqual(orphans, []);
    db.close();
  });

  it('drops historic indexes that the current schema no longer declares', () => {
    // First schema declares a `status` index.
    backend.ensureBook(
      { ownerId: OWNER, book: BOOK },
      { indexes: ['status'] },
    );
    const table = tableName({ ownerId: OWNER, book: BOOK });

    // Confirm the index exists.
    {
      const db = inspectDb(env.home);
      assert.ok(indexesForTable(db, table).some((n) => n.includes('status')));
      db.close();
    }

    // Drop the book — must drop the historic `status` index even though
    // we never re-declared it before dropping. dropBook is wholesale.
    backend.dropBook({ ownerId: OWNER, book: BOOK });

    const db = inspectDb(env.home);
    assert.deepStrictEqual(tablesByPrefix(db, table), []);
    assert.deepStrictEqual(indexesForTable(db, table), []);
    db.close();
  });

  it('is idempotent at the backend level', () => {
    backend.ensureBook({ ownerId: OWNER, book: BOOK }, {});
    backend.dropBook({ ownerId: OWNER, book: BOOK });
    // Second call must not throw.
    assert.doesNotThrow(() => backend.dropBook({ ownerId: OWNER, book: BOOK }));
    // A drop on a never-existed book must also not throw.
    assert.doesNotThrow(() =>
      backend.dropBook({ ownerId: OWNER, book: 'never-existed' }),
    );
  });
});

