1	/**
2	 * The Lattice — notification substrate apparatus.
3	 *
4	 * The Lattice owns the `lattice/pulses` book, exposes a small `LatticeApi`
5	 * for emitters, consumes a new `latticeChannels` kit contribution type
6	 * (channel factories), and fans newly-emitted pulses out via a Phase 2 CDC
7	 * watcher on its own pulses book.
8	 *
9	 * Phase 2 dispatch is deliberate:
10	 *
11	 *   1. Channel I/O is a side effect layered on top of a persistent event
12	 *      record. A `send()` failure (HTTP 5xx, network drop, etc.) must not
13	 *      roll back the underlying pulse write — the pulse is the durable
14	 *      record; dispatch is best-effort.
15	 *   2. The dispatcher patches `deliveryState` on the same book it watches.
16	 *      Phase 1 would re-enter the CDC dispatch and risk recursion; Phase 2
17	 *      runs post-commit, so the delivery-state update fires cleanly on the
18	 *      next cycle (and is ignored by the dispatcher, which only reacts to
19	 *      create events and to update events that move a pulse off `pending`
20	 *      are no-ops — see the handler body).
21	 *
22	 * Pulses are immutable from the public API's perspective. The Lattice itself
23	 * writes `deliveryState` transitions (pending → delivered/failed). `show`,
24	 * `list`, `count`, and `resolveId` round out the read surface.
25	 *
26	 * See: docs/architecture/apparatus/lattice.md
27	 */
28	
29	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
30	import { guild, generateId } from '@shardworks/nexus-core';
31	import type { Book, StacksApi, WhereClause } from '@shardworks/stacks-apparatus';
32	
33	import type {
34	  EmitPulseRequest,
35	  LatticeApi,
36	  LatticeChannel,
37	  LatticeChannelFactory,
38	  LatticeChannelInstanceConfig,
39	  LatticeConfig,
40	  PulseDoc,
41	  PulseFilters,
42	} from './types.ts';
43	
44	import { pulseList, pulseShow } from './tools/index.ts';
45	
46	// ── Kit contribution vocabulary ─────────────────────────────────────
47	
48	const LATTICE_CHANNELS_KIT = 'latticeChannels';
49	
50	// ── Factory registration ────────────────────────────────────────────
51	
52	interface RegisteredFactory {
53	  pluginId: string;
54	  factory: LatticeChannelFactory;
55	}
56	
57	export function createLattice(): Plugin {
58	  let stacks: StacksApi;
59	  let pulses: Book<PulseDoc>;
60	
61	  // Registered channel factories keyed by `type` — first writer wins, with
62	  // a warning for duplicates.
63	  const factories = new Map<string, RegisteredFactory>();
64	
65	  // Materialized channel instances drawn from guild config, in the order
66	  // they appear in `lattice.channels`. One entry per configured instance.
67	  const channels: LatticeChannel[] = [];
68	
69	  /**
70	   * Build a where clause from PulseFilters. Shared between list() and
71	   * count().
72	   */
73	  function buildWhereClause(filters?: PulseFilters): WhereClause | undefined {
74	    const conditions: WhereClause = [];
75	    if (filters?.triggerType) {
76	      const types = Array.isArray(filters.triggerType) ? filters.triggerType : [filters.triggerType];
77	      if (types.length === 1) {
78	        conditions.push(['triggerType', '=', types[0]!]);
79	      } else if (types.length > 1) {
80	        conditions.push(['triggerType', 'IN', types]);
81	      }
82	    }
83	    if (filters?.source) {
84	      conditions.push(['source', '=', filters.source]);
85	    }
86	    if (filters?.since) {
87	      conditions.push(['createdAt', '>=', filters.since]);
88	    }
89	    if (filters?.until) {
90	      conditions.push(['createdAt', '<=', filters.until]);
91	    }
92	    if (filters?.deliveryState) {
93	      const states = Array.isArray(filters.deliveryState) ? filters.deliveryState : [filters.deliveryState];
94	      if (states.length === 1) {
95	        conditions.push(['deliveryState', '=', states[0]!]);
96	      } else if (states.length > 1) {
97	        conditions.push(['deliveryState', 'IN', states]);
98	      }
99	    }
100	    return conditions.length > 0 ? conditions : undefined;
101	  }
102	
103	  // ── API ────────────────────────────────────────────────────────
104	
105	  const api: LatticeApi = {
106	    async emit(request: EmitPulseRequest): Promise<PulseDoc> {
107	      if (!request.source) {
108	        throw new Error('LatticeApi.emit: request.source is required.');
109	      }
110	      if (!request.triggerType) {
111	        throw new Error('LatticeApi.emit: request.triggerType is required.');
112	      }
113	      if (typeof request.title !== 'string' || request.title.length === 0) {
114	        throw new Error('LatticeApi.emit: request.title must be a non-empty string.');
115	      }
116	      if (typeof request.summary !== 'string') {
117	        throw new Error('LatticeApi.emit: request.summary must be a string.');
118	      }
119	
120	      const now = new Date().toISOString();
121	      const pulse: PulseDoc = {
122	        id: generateId('p', 6),
123	        source: request.source,
124	        triggerType: request.triggerType,
125	        writId: request.writId ?? null,
126	        title: request.title,
127	        summary: request.summary,
128	        linkUrl: request.linkUrl ?? null,
129	        context: request.context ?? {},
130	        deliveryState: 'pending',
131	        createdAt: now,
132	        updatedAt: now,
133	      };
134	
135	      await pulses.put(pulse);
136	      return pulse;
137	    },
138	
139	    async show(id: string): Promise<PulseDoc> {
140	      const pulse = await pulses.get(id);
141	      if (!pulse) {
142	        throw new Error(`Pulse "${id}" not found.`);
143	      }
144	      return pulse;
145	    },
146	
147	    async resolveId(prefix: string): Promise<string> {
148	      const exact = await pulses.get(prefix);
149	      if (exact) return exact.id;
150	
151	      const results = await pulses.find({ where: [['id', 'LIKE', prefix + '%']] });
152	      if (results.length === 0) {
153	        throw new Error(`No pulse found matching prefix "${prefix}".`);
154	      }
155	      if (results.length > 1) {
156	        throw new Error(`Ambiguous prefix "${prefix}": matches ${results.length} pulses.`);
157	      }
158	      return results[0]!.id;
159	    },
160	
161	    async list(filters?: PulseFilters): Promise<PulseDoc[]> {
162	      // Default `since` to 24h before now when the caller supplies no
163	      // lower bound — the brief prescribes a 24h window for `pulse list`.
164	      const effectiveFilters: PulseFilters = { ...(filters ?? {}) };
165	      if (effectiveFilters.since === undefined) {
166	        effectiveFilters.since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
167	      }
168	      const where = buildWhereClause(effectiveFilters);
169	      const limit = effectiveFilters.limit ?? 20;
170	      const offset = effectiveFilters.offset;
171	
172	      return pulses.find({
173	        where,
174	        // Tie-break on `id` so same-ms emissions produce a deterministic order.
175	        // Pulse ids carry a base36 timestamp prefix and a random suffix; sorting
176	        // them desc after createdAt desc yields a total order that is stable
177	        // across repeated calls.
178	        orderBy: [['createdAt', 'desc'], ['id', 'desc']],
179	        limit,
180	        ...(offset !== undefined ? { offset } : {}),
181	      });
182	    },
183	
184	    async count(filters?: PulseFilters): Promise<number> {
185	      const where = buildWhereClause(filters);
186	      return pulses.count(where);
187	    },
188	  };
189	
190	  // ── Channel registration ─────────────────────────────────────
191	
192	  function registerKitChannels(entry: { pluginId: string; value: unknown }): void {
193	    const { pluginId } = entry;
194	    const raw = entry.value;
195	    if (!Array.isArray(raw)) {
196	      console.warn(
197	        `[lattice] Kit "${pluginId}" latticeChannels: expected an array, got ${typeof raw} — skipped.`,
198	      );
199	      return;
200	    }
201	
202	    for (const candidate of raw) {
203	      if (typeof candidate !== 'object' || candidate === null) {
204	        console.warn(
205	          `[lattice] Kit "${pluginId}" latticeChannels: entry is not an object — skipped.`,
206	        );
207	        continue;
208	      }
209	      const factory = candidate as Partial<LatticeChannelFactory>;
210	      if (typeof factory.type !== 'string' || factory.type.length === 0) {
211	        console.warn(
212	          `[lattice] Kit "${pluginId}" latticeChannels: entry is missing a non-empty "type" string — skipped.`,
213	        );
214	        continue;
215	      }
216	      if (typeof factory.create !== 'function') {
217	        console.warn(
218	          `[lattice] Kit "${pluginId}" latticeChannels: entry "${factory.type}" is missing a "create" function — skipped.`,
219	        );
220	        continue;
221	      }
222	      if (factories.has(factory.type)) {
223	        const existing = factories.get(factory.type)!;
224	        console.warn(
225	          `[lattice] Kit "${pluginId}" latticeChannels: factory type "${factory.type}" is already registered by kit "${existing.pluginId}" — duplicate skipped.`,
226	        );
227	        continue;
228	      }
229	      factories.set(factory.type, {
230	        pluginId,
231	        factory: factory as LatticeChannelFactory,
232	      });
233	    }
234	  }
235	
236	  function materializeChannels(config: LatticeConfig | undefined): void {
237	    channels.length = 0;
238	    const entries = config?.channels ?? [];
239	    for (const instance of entries) {
240	      if (typeof instance !== 'object' || instance === null) {
241	        console.warn(`[lattice] lattice.channels: entry is not an object — skipped.`);
242	        continue;
243	      }
244	      const typed = instance as LatticeChannelInstanceConfig;
245	      const factoryEntry = factories.get(typed.type);
246	      if (!factoryEntry) {
247	        console.warn(
248	          `[lattice] lattice.channels: no factory registered for type "${typed.type}" — skipped. ` +
249	            `Known types: ${factories.size === 0 ? '(none)' : [...factories.keys()].join(', ')}.`,
250	        );
251	        continue;
252	      }
253	      try {
254	        const channel = factoryEntry.factory.create(typed);
255	        channels.push(channel);
256	      } catch (err) {
257	        const msg = err instanceof Error ? err.message : String(err);
258	        console.warn(
259	          `[lattice] lattice.channels: factory "${typed.type}" failed to create a channel: ${msg} — skipped.`,
260	        );
261	      }
262	    }
263	  }
264	
265	  // ── Dispatch ────────────────────────────────────────────────
266	
267	  /**
268	   * Deliver a single pulse to every configured channel.
269	   *
270	   * Per D8 (best-effort one-shot): the pulse's deliveryState moves to
271	   * `delivered` only if every channel returned ok=true; a single failure
272	   * (ok=false or a thrown error) marks the pulse `failed`. Errors are
273	   * captured as text on `deliveryError`; no retry is attempted.
274	   *
275	   * If no channels are configured we still patch deliveryState so pulses
276	   * do not sit as `pending` forever — with no channels, "delivered" is
277	   * the best available status ("nothing failed"). Operators can always
278	   * see the emission in `nsg pulse list` regardless.
279	   */
280	  async function dispatch(pulse: PulseDoc): Promise<void> {
281	    // Re-read in case it was already dispatched (startup scan races,
282	    // duplicated CDC deliveries from the backend, etc.).
283	    const current = await pulses.get(pulse.id);
284	    if (!current) return;
285	    if (current.deliveryState !== 'pending') return;
286	
287	    const errors: string[] = [];
288	    for (const channel of channels) {
289	      try {
290	        const outcome = await channel.send(current);
291	        if (!outcome.ok) {
292	          errors.push(`${channel.type}: ${outcome.error}`);
293	        }
294	      } catch (err) {
295	        // A well-behaved channel never throws, but defence in depth —
296	        // we do not allow channel errors to bubble past the dispatcher.
297	        const msg = err instanceof Error ? err.message : String(err);
298	        errors.push(`${channel.type}: ${msg}`);
299	      }
300	    }
301	
302	    const now = new Date().toISOString();
303	    if (errors.length === 0) {
304	      await pulses.patch(pulse.id, {
305	        deliveryState: 'delivered',
306	        updatedAt: now,
307	      });
308	    } else {
309	      await pulses.patch(pulse.id, {
310	        deliveryState: 'failed',
311	        deliveryError: errors.join('; '),
312	        updatedAt: now,
313	      });
314	    }
315	  }
316	
317	  return {
318	    apparatus: {
319	      requires: ['stacks'],
320	      // Oculus is only a soft dependency for a future patron-facing page;
321	      // the Lattice runs fine without it.
322	      recommends: ['oculus'],
323	      consumes: [LATTICE_CHANNELS_KIT],
324	
325	      provides: api,
326	
327	      supportKit: {
328	        books: {
329	          pulses: {
330	            indexes: [
331	              'triggerType',
332	              'source',
333	              'createdAt',
334	              'deliveryState',
335	              'writId',
336	              ['deliveryState', 'createdAt'],
337	              ['triggerType', 'createdAt'],
338	            ],
339	          },
340	        },
341	        tools: [pulseList, pulseShow],
342	      },
343	
344	      async start(ctx: StartupContext): Promise<void> {
345	        const g = guild();
346	        stacks = g.apparatus<StacksApi>('stacks');
347	        pulses = stacks.book<PulseDoc>('lattice', 'pulses');
348	
349	        // Scan all kit-contributed channel factories.
350	        factories.clear();
351	        for (const entry of ctx.kits(LATTICE_CHANNELS_KIT)) {
352	          registerKitChannels(entry);
353	        }
354	
355	        // Materialize channels from guild config.
356	        const config = g.guildConfig().lattice;
357	        materializeChannels(config);
358	
359	        // Phase 2 (post-commit) CDC watcher on the pulses book. See the
360	        // file comment for why Phase 2 is deliberate. The handler only
361	        // reacts to create events and to updates that re-enter `pending`
362	        // (which should not happen in practice — deliveryState is
363	        // monotonic once it leaves `pending` — but we guard anyway).
364	        stacks.watch<PulseDoc>(
365	          'lattice',
366	          'pulses',
367	          async (event) => {
368	            if (event.type !== 'create' && event.type !== 'update') return;
369	            const pulse = event.entry;
370	            if (pulse.deliveryState !== 'pending') return;
371	            if (event.type === 'update' && event.prev.deliveryState === 'pending') {
372	              // An in-place update that left the pulse `pending` — e.g. a
373	              // future editor re-wrote summary. Do not re-dispatch.
374	              return;
375	            }
376	            await dispatch(pulse);
377	          },
378	          { failOnError: false },
379	        );
380	
381	        // Startup scan — any pulse left in `pending` across a restart gets
382	        // another dispatch pass. Runs out-of-band from the CDC handler so
383	        // the usual post-commit path handles new emissions while we
384	        // mop up the backlog.
385	        const pending = await pulses.find({
386	          where: [['deliveryState', '=', 'pending']],
387	          orderBy: ['createdAt', 'asc'],
388	        });
389	        for (const pulse of pending) {
390	          // Swallow errors individually — one bad pulse must not stop
391	          // the scan.
392	          try {
393	            await dispatch(pulse);
394	          } catch (err) {
395	            const msg = err instanceof Error ? err.message : String(err);
396	            console.warn(`[lattice] startup scan: dispatch of "${pulse.id}" failed: ${msg}`);
397	          }
398	        }
399	      },
400	    },
401	  };
402	}
