193	// ── Factory ──────────────────────────────────────────────────────────
194	
195	export function createCartograph(): Plugin {
196	  let stacks: StacksApi;
197	  let clerk: ClerkApi;
198	
199	  // ── Generic helpers ────────────────────────────────────────────────
200	
201	  /**
202	   * Read the cartograph sub-slot off a writ. Returns `undefined` when
203	   * the slot is absent — the show paths interpret that as fail-loud,
204	   * and the list paths interpret it as a tolerant `stage: undefined`
205	   * projection (D7 + D18 in the commission spec).
206	   */
207	  function readCartographExt(writ: WritDoc): CartographExt | undefined {
208	    const slot = writ.ext?.[CARTOGRAPH_PLUGIN_ID];
209	    if (slot === undefined || slot === null) return undefined;
210	    if (typeof slot !== 'object') return undefined;
211	    return slot as CartographExt;
212	  }
213	
214	  /**
215	   * Build the typed projection for a writ. Throws when the
216	   * `ext['cartograph']` slot is missing — the typed-API contract is
217	   * that every cartograph-typed writ stamped through `createX` carries
218	   * the slot, so a missing slot indicates the contract was bypassed.
219	   */
220	  function projectVision(writ: WritDoc): VisionDoc {
221	    const ext = readCartographExt(writ);
222	    if (ext === undefined) {
223	      throw new Error(
224	        `Vision "${writ.id}" not found: writ exists but is missing its ext['${CARTOGRAPH_PLUGIN_ID}'] sub-slot. ` +
225	          `The cartograph typed API is the only sanctioned path that stamps this slot — was the writ posted via raw clerk.post?`,
226	      );
227	    }
228	    return {
229	      id: writ.id,
230	      stage: ext.stage as VisionStage,
231	      ...(writ.codex !== undefined ? { codex: writ.codex } : {}),
232	      createdAt: writ.createdAt,
233	      updatedAt: writ.updatedAt,
234	    };
235	  }
236	
237	  function projectCharge(writ: WritDoc): ChargeDoc {
238	    const ext = readCartographExt(writ);
239	    if (ext === undefined) {
240	      throw new Error(
241	        `Charge "${writ.id}" not found: writ exists but is missing its ext['${CARTOGRAPH_PLUGIN_ID}'] sub-slot. ` +
242	          `The cartograph typed API is the only sanctioned path that stamps this slot — was the writ posted via raw clerk.post?`,
243	      );
244	    }
245	    return {
246	      id: writ.id,
247	      stage: ext.stage as ChargeStage,
248	      ...(writ.codex !== undefined ? { codex: writ.codex } : {}),
249	      createdAt: writ.createdAt,
250	      updatedAt: writ.updatedAt,
251	    };
252	  }
253	
254	  function projectPiece(writ: WritDoc): PieceDoc {
255	    const ext = readCartographExt(writ);
256	    if (ext === undefined) {
257	      throw new Error(
258	        `Piece "${writ.id}" not found: writ exists but is missing its ext['${CARTOGRAPH_PLUGIN_ID}'] sub-slot. ` +
259	          `The cartograph typed API is the only sanctioned path that stamps this slot — was the writ posted via raw clerk.post?`,
260	      );
261	    }
262	    return {
263	      id: writ.id,
264	      stage: ext.stage as PieceStage,
265	      ...(writ.codex !== undefined ? { codex: writ.codex } : {}),
266	      createdAt: writ.createdAt,
267	      updatedAt: writ.updatedAt,
268	    };
269	  }
270	
271	  /**
272	   * Tolerant projection used by listX endpoints (per D18). When the
273	   * `ext['cartograph']` slot is absent — a writ posted via raw
274	   * `clerk.post` rather than the typed API — the row still appears in
275	   * results with `stage: undefined`. Listing is a tolerant read; the
276	   * fail-loud behavior lives at showX (per D7).
277	   */
278	  function tolerantProjectVision(writ: WritDoc): VisionDoc {
279	    const ext = readCartographExt(writ);
280	    return {
281	      id: writ.id,
282	      stage: ext?.stage as VisionStage,
283	      ...(writ.codex !== undefined ? { codex: writ.codex } : {}),
284	      createdAt: writ.createdAt,
285	      updatedAt: writ.updatedAt,
286	    };
287	  }
288	
289	  function tolerantProjectCharge(writ: WritDoc): ChargeDoc {
290	    const ext = readCartographExt(writ);
291	    return {
292	      id: writ.id,
293	      stage: ext?.stage as ChargeStage,
294	      ...(writ.codex !== undefined ? { codex: writ.codex } : {}),
295	      createdAt: writ.createdAt,
296	      updatedAt: writ.updatedAt,
297	    };
298	  }
299	
300	  function tolerantProjectPiece(writ: WritDoc): PieceDoc {
301	    const ext = readCartographExt(writ);
302	    return {
303	      id: writ.id,
304	      stage: ext?.stage as PieceStage,
305	      ...(writ.codex !== undefined ? { codex: writ.codex } : {}),
306	      createdAt: writ.createdAt,
307	      updatedAt: writ.updatedAt,
308	    };
309	  }
310	
311	  /**
312	   * Validate parent existence, not-terminal, and (optionally) the parent's
313	   * type. Returns the parent writ doc on success. The transactional
314	   * writs-book handle is passed in by the caller so all reads/writes
315	   * commit under a single boundary.
316	   */
317	  async function validateParent(
318	    txWritsBook: { get(id: string): Promise<WritDoc | null> },
319	    parentId: string,
320	    childId: string,
321	    options: { allowedParentTypes?: string[]; childTypeName: string },
322	  ): Promise<WritDoc> {
323	    const parent = await txWritsBook.get(parentId);
324	    if (!parent) {
325	      throw new Error(`Parent writ "${parentId}" not found.`);
326	    }
327	    if (parentId === childId) {
328	      throw new Error(`Cannot create a writ as its own parent.`);
329	    }
330	    if (isTerminalPhase(parent, (name) => clerk.getWritTypeConfig(name))) {
331	      throw new Error(
332	        `Cannot add children to writ "${parentId}": phase is "${parent.phase}" (terminal). Children can only be added to writs in non-terminal states.`,
333	      );
334	    }
335	    if (options.allowedParentTypes !== undefined) {
336	      if (!options.allowedParentTypes.includes(parent.type)) {
337	        const allowed = options.allowedParentTypes.map((t) => `"${t}"`).join(' or ');
338	        throw new Error(
339	          `[cartograph] cannot create ${options.childTypeName} under writ "${parentId}": parent type is "${parent.type}", expected ${allowed}.`,
340	        );
341	      }
342	    }
343	    return parent;
344	  }
345	
346	  /**
347	   * Build the where-clause used by listX endpoints. The `stage` filter
348	   * uses the dot-notation field `ext.cartograph.stage` — Stacks'
349	   * SQLite backend translates dotted field names into `json_extract`
350	   * calls (see the tier3 conformance suite). Per D5, the writs book
351	   * carries no index on this field; cartograph row counts are small,
352	   * so the unindexed scan is acceptable.
353	   */
354	  function buildListWhere(filters: { stage?: string; codex?: string } | undefined, type: string): WhereClause {
355	    const conditions: WhereClause = [['type', '=', type]];
356	    if (filters?.stage !== undefined) {
357	      conditions.push([`ext.${CARTOGRAPH_PLUGIN_ID}.stage`, '=', filters.stage]);
358	    }
359	    if (filters?.codex !== undefined) {
360	      conditions.push(['codex', '=', filters.codex]);
361	    }
362	    return conditions;
363	  }
364	
365	  // ── API ────────────────────────────────────────────────────────────
366	
367	  const api: CartographApi = {
368	    // ── Vision ────────────────────────────────────────────────────
369	
370	    async createVision(request: CreateVisionRequest): Promise<VisionDoc> {
371	      // Runtime guard for the typed-API parent invariant: a vision has
372	      // no parent. The static `CreateVisionRequest` shape does not
373	      // include `parentId`, but a structurally-typed caller could still
374	      // pass one — reject explicitly so the rule is enforced at the
375	      // boundary.
376	      const maybeParentId = (request as { parentId?: unknown }).parentId;
377	      if (typeof maybeParentId === 'string' && maybeParentId.length > 0) {
378	        throw new Error(
379	          '[cartograph] createVision: a vision is a top-level writ and cannot have a parent — refusing to create a vision with parentId.',
380	        );
381	      }
382	
383	      // Initial-state resolution. Defaults to (phase=new, stage=draft) so
384	      // existing callers are unaffected. A caller may supply either or
385	      // both; whatever they supply must agree with the fixed mapping in
386	      // VISION_INITIAL_STAGE_TO_PHASE. Terminal initial states
387	      // (sunset/cancelled) are rejected — a vision cannot be born retired.
388	      const requestedStage: VisionStage = request.stage ?? INITIAL_STAGE;
389	      const expectedPhase = VISION_INITIAL_STAGE_TO_PHASE[requestedStage];
390	      if (expectedPhase === undefined) {
391	        throw new Error(
392	          `[cartograph] createVision: stage "${requestedStage}" is not a valid initial stage. ` +
393	            `A vision cannot be born retired — allowed initial stages are "draft" and "active". ` +
394	            `To drive a vision to a terminal state, create it then call transitionVision.`,
395	        );
396	      }
397	      const requestedPhase: WritPhase = request.phase ?? expectedPhase;
398	      if (requestedPhase !== expectedPhase) {
399	        throw new Error(
400	          `[cartograph] createVision: phase "${requestedPhase}" does not pair with stage "${requestedStage}". ` +
401	            `Allowed initial pairs are (phase=new, stage=draft) and (phase=open, stage=active).`,
402	        );
403	      }
404	      // Validate phase against the registered VISION_CONFIG, mirroring
405	      // transitionVision's defensive check. Catches an unregistered or
406	      // typo'd phase value before we write the writ row.
407	      const visionConfig = clerk.getWritTypeConfig('vision');
408	      if (!visionConfig) {
409	        throw new Error(
410	          '[cartograph] createVision: writ type "vision" is not registered with the Clerk.',
411	        );
412	      }
413	      const requestedState = visionConfig.states.find((s) => s.name === requestedPhase);
414	      if (!requestedState) {
415	        throw new Error(
416	          `[cartograph] createVision: phase "${requestedPhase}" is not declared in writ type "vision".`,
417	        );
418	      }
419	
420	      // The createX methods cannot delegate to clerk.post because Clerk's
421	      // `post` does not accept an external transaction context, and the
422	      // writ row + ext['cartograph'] stamp must commit under one boundary.
423	      // Replicating Clerk's validation logic here is the cost of being a
424	      // typed atomic surface.
425	      return stacks.transaction(async (tx) => {
426	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
427	
428	        const childId = generateId('w', 6);
429	        const now = new Date().toISOString();
430	
431	        const writ: WritDoc = {
432	          id: childId,
433	          type: 'vision',
434	          phase: requestedPhase,
435	          title: request.title,
436	          body: request.body,
437	          ...(request.codex !== undefined ? { codex: request.codex } : {}),
438	          createdAt: now,
439	          updatedAt: now,
440	        };
441	
442	        await txWritsBook.put(writ);
443	
444	        // setWritExt opens its own inner tx; nested-tx semantics flatten
445	        // it into the outer tx so both writes coalesce to one CDC create
446	        // event with the final state (writ fields + ext['cartograph']).
447	        const stamped = await clerk.setWritExt(
448	          childId,
449	          CARTOGRAPH_PLUGIN_ID,
450	          { stage: requestedStage } satisfies CartographExt,
451	        );
452	        return projectVision(stamped);
453	      });
454	    },
455	
456	    async showVision(id: string): Promise<VisionDoc> {
457	      const writ = await clerk.show(id);
458	      if (writ.type !== 'vision') {
459	        throw new Error(`Vision "${id}" not found (writ exists but type is "${writ.type}").`);
460	      }
461	      return projectVision(writ);
462	    },
463	
464	    async listVisions(filters?: VisionFilters): Promise<VisionDoc[]> {
465	      const writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
466	      const rows = await writsBook.find({
467	        where: buildListWhere(filters, 'vision'),
468	        orderBy: ['createdAt', 'desc'],
469	        limit: filters?.limit ?? 20,
470	        ...(filters?.offset !== undefined ? { offset: filters.offset } : {}),
471	      });
472	      return rows.map(tolerantProjectVision);
473	    },
474	
475	    async patchVision(
476	      id: string,
477	      fields: Partial<Omit<VisionDoc, 'id'>>,
478	    ): Promise<VisionDoc> {
479	      // Codex flows through `clerk.edit` so the writ row stays the
480	      // single source of truth (D2). Stage flows through `setWritExt`
481	      // so sibling sub-slots are preserved (per the setWritExt
482	      // contract). Both writes target the same writ row; if both are
483	      // requested they coalesce to one CDC update event.
484	      return stacks.transaction(async () => {
485	        // The projection type carries `[key: string]: unknown` (D6) so
486	        // property access on `fields` widens to `unknown`. Cast at the
487	        // boundary; the typed-API contract is that callers supply
488	        // string codex / stage values matching the projection.
489	        const codex = fields.codex as string | undefined;
490	        const stage = fields.stage as VisionStage | undefined;
491	        if (codex !== undefined) {
492	          await clerk.edit({ id, codex });
493	        }
494	        if (stage !== undefined) {
495	          await clerk.setWritExt(
496	            id,
497	            CARTOGRAPH_PLUGIN_ID,
498	            { stage } satisfies CartographExt,
499	          );
500	        }
501	        // Re-read so the returned projection reflects every write
502	        // performed in this tx (including the fall-through case where
503	        // neither codex nor stage was supplied — the projection still
504	        // returns the current state).
505	        const writ = await clerk.show(id);
506	        return projectVision(writ);
507	      });
508	    },
509	
510	    async transitionVision(
511	      id: string,
512	      request: TransitionVisionRequest,
513	    ): Promise<VisionDoc> {
514	      // Lifecycle coupling: the writ phase patch and the
515	      // `ext['cartograph'].stage` stamp must commit atomically. Both
516	      // `clerk.transition` and `clerk.setWritExt` open their own inner
517	      // transactions; under Stacks' nested-tx semantics they flatten
518	      // into this outer tx, so CDC sees one coalesced update event.
519	      return stacks.transaction(async () => {
520	        const transitionFields: Partial<WritDoc> = {};
521	        if (request.resolution !== undefined) {
522	          transitionFields.resolution = request.resolution;
523	        }
524	        await clerk.transition(id, request.phase, transitionFields);
525	
526	        const stamped = await clerk.setWritExt(
527	          id,
528	          CARTOGRAPH_PLUGIN_ID,
529	          { stage: request.stage } satisfies CartographExt,
530	        );
531	        return projectVision(stamped);
532	      });
533	    },
534	
535	    // ── Charge ────────────────────────────────────────────────────
536	
537	    async createCharge(request: CreateChargeRequest): Promise<ChargeDoc> {
538	      return stacks.transaction(async (tx) => {
539	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
540	
541	        const childId = generateId('w', 6);
542	        const now = new Date().toISOString();
543	        const initialPhase = 'new';
544	
545	        if (!request.parentId) {
546	          throw new Error(
547	            '[cartograph] createCharge requires a parentId — a charge must be created under a vision.',
548	          );
549	        }
550	
551	        const parent = await validateParent(txWritsBook, request.parentId, childId, {
552	          allowedParentTypes: ['vision'],
553	          childTypeName: 'charge',
554	        });
555	
556	        const codex = request.codex ?? parent.codex;
557	
558	        const writ: WritDoc = {
559	          id: childId,
560	          type: 'charge',
561	          phase: initialPhase,
562	          title: request.title,
563	          body: request.body,
564	          ...(codex !== undefined ? { codex } : {}),
565	          parentId: request.parentId,
566	          createdAt: now,
567	          updatedAt: now,
568	        };
569	
570	        await txWritsBook.put(writ);
571	
572	        const stamped = await clerk.setWritExt(
573	          childId,
574	          CARTOGRAPH_PLUGIN_ID,
575	          { stage: INITIAL_STAGE } satisfies CartographExt,
576	        );
577	        return projectCharge(stamped);
578	      });
579	    },
580	
581	    async showCharge(id: string): Promise<ChargeDoc> {
582	      const writ = await clerk.show(id);
583	      if (writ.type !== 'charge') {
584	        throw new Error(`Charge "${id}" not found (writ exists but type is "${writ.type}").`);
585	      }
586	      return projectCharge(writ);
587	    },
588	
589	    async listCharges(filters?: ChargeFilters): Promise<ChargeDoc[]> {
590	      const writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
591	      const rows = await writsBook.find({
592	        where: buildListWhere(filters, 'charge'),
593	        orderBy: ['createdAt', 'desc'],
594	        limit: filters?.limit ?? 20,
595	        ...(filters?.offset !== undefined ? { offset: filters.offset } : {}),
596	      });
597	      return rows.map(tolerantProjectCharge);
598	    },
599	
600	    async patchCharge(
601	      id: string,
602	      fields: Partial<Omit<ChargeDoc, 'id'>>,
603	    ): Promise<ChargeDoc> {
604	      return stacks.transaction(async () => {
605	        const codex = fields.codex as string | undefined;
606	        const stage = fields.stage as ChargeStage | undefined;
607	        if (codex !== undefined) {
608	          await clerk.edit({ id, codex });
609	        }
610	        if (stage !== undefined) {
611	          await clerk.setWritExt(
612	            id,
613	            CARTOGRAPH_PLUGIN_ID,
614	            { stage } satisfies CartographExt,
615	          );
616	        }
617	        const writ = await clerk.show(id);
618	        return projectCharge(writ);
619	      });
620	    },
621	
622	    async transitionCharge(
623	      id: string,
624	      request: TransitionChargeRequest,
625	    ): Promise<ChargeDoc> {
626	      return stacks.transaction(async () => {
627	        const transitionFields: Partial<WritDoc> = {};
628	        if (request.resolution !== undefined) {
629	          transitionFields.resolution = request.resolution;
630	        }
631	        await clerk.transition(id, request.phase, transitionFields);
632	
633	        const stamped = await clerk.setWritExt(
